"use client";

import * as React from "react";
import { Moon, Sun, Monitor, ChevronDown } from "lucide-react";
import { useTheme } from "next-themes";
import { motion, AnimatePresence } from "framer-motion";

export function ThemeSwitcher() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = React.useState(false);
  const [isMobile, setIsMobile] = React.useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = React.useState(false);
  const dropdownRef = React.useRef<HTMLDivElement>(null);

  const options = [
    { name: "light", icon: Sun, label: "Light" },
    { name: "system", icon: Monitor, label: "System" },
    { name: "dark", icon: Moon, label: "Dark" },
  ];

  // Avoid hydration mismatch
  React.useEffect(() => {
    setMounted(true);
    
    const handleResize = () => {
      setIsMobile(window.innerWidth < 385);
    };
    
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Close dropdown when clicking outside
  React.useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  if (!mounted) return <div className="h-10 w-10 sm:w-28 animate-pulse bg-gray-100 dark:bg-slate-800 rounded-xl" />;

  const ActiveIcon = options.find(o => o.name === theme)?.icon || Monitor;

  // MOBILE VIEW (< 385px)
  if (isMobile) {
    return (
      <div className="relative" ref={dropdownRef}>
        <button
          onClick={() => setIsDropdownOpen(!isDropdownOpen)}
          className="flex items-center justify-center w-10 h-10 rounded-xl bg-gray-100 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-emerald-600 dark:text-emerald-400 transition-all active:scale-95"
        >
          <ActiveIcon size={18} />
        </button>

        <AnimatePresence>
          {isDropdownOpen && (
            <motion.div
              initial={{ opacity: 0, y: 10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 10, scale: 0.95 }}
              className="absolute right-0 mt-2 w-36 bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl shadow-2xl z-[150] overflow-hidden"
            >
              <div className="p-1.5 space-y-1">
                {options.map((option) => {
                  const isActive = theme === option.name;
                  const Icon = option.icon;
                  return (
                    <button
                      key={option.name}
                      onClick={() => {
                        setTheme(option.name);
                        setIsDropdownOpen(false);
                      }}
                      className={`flex items-center w-full space-x-3 px-3 py-2.5 rounded-xl transition-all ${
                        isActive 
                          ? "bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 font-bold" 
                          : "text-slate-500 dark:text-slate-400 hover:bg-gray-50 dark:hover:bg-slate-800"
                      }`}
                    >
                      <Icon size={16} />
                      <span className="text-[11px] uppercase tracking-widest">{option.label}</span>
                    </button>
                  );
                })}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    );
  }

  // STANDARD VIEW (> 385px)
  return (
    <div className="flex items-center p-1 bg-gray-100 dark:bg-slate-800 rounded-xl border border-gray-200 dark:border-slate-700 transition-all duration-300">
      {options.map((option) => {
        const isActive = theme === option.name;
        const Icon = option.icon;
        
        return (
          <button
            key={option.name}
            onClick={() => setTheme(option.name)}
            className={`flex items-center justify-center w-9 h-8 rounded-lg transition-all duration-200 ${
              isActive 
                ? "bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-sm ring-1 ring-black/5" 
                : "text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100"
            }`}
            title={option.label}
          >
            <Icon size={16} />
          </button>
        );
      })}
    </div>
  );
}
